package com.example.prototype;

import android.os.Handler;
import android.os.Looper;

import androidx.annotation.NonNull;

import java.util.UUID;

public final class AuthRepository {

    public interface Callback {
        void onResult(@NonNull LoginResult result);
    }

    public void login(@NonNull String email, @NonNull String password, @NonNull Callback callback) {
        new Handler(Looper.getMainLooper()).postDelayed(() -> {
            String e = email.trim();
            String p = password;

            if (!isValidEmail(e)) {
                callback.onResult(LoginResult.error("Invalid email"));
                return;
            }
            if (p.length() < 4) {
                callback.onResult(LoginResult.error("Password too short"));
                return;
            }

            String token = "demo_" + UUID.randomUUID().toString();
            callback.onResult(LoginResult.success(e, token));
        }, 700);
    }

    private boolean isValidEmail(String email) {
        int at = email.indexOf('@');
        int dot = email.lastIndexOf('.');
        return at > 0 && dot > at + 1 && dot < email.length() - 1;
    }
}

package com.example.prototype;

import android.content.Intent;
import android.os.Bundle;
import android.text.TextUtils;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ProgressBar;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {

    private EditText emailInput;
    private EditText passwordInput;
    private Button loginButton;
    private ProgressBar progress;
    private TextView errorText;

    private final AuthRepository authRepository = new AuthRepository();

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (AuthPrefs.isLoggedIn(this)) {
            startActivity(new Intent(this, MainActivity.class));
            finish();
            return;
        }

        setContentView(R.layout.activity_login);

        emailInput = findViewById(R.id.emailInput);
        passwordInput = findViewById(R.id.passwordInput);
        loginButton = findViewById(R.id.loginButton);
        progress = findViewById(R.id.progress);
        errorText = findViewById(R.id.errorText);

        String lastEmail = AuthPrefs.getEmail(this);
        if (!TextUtils.isEmpty(lastEmail)) emailInput.setText(lastEmail);

        loginButton.setOnClickListener(v -> attemptLogin());
    }

    private void attemptLogin() {
        setLoading(true);
        setError(null);

        String email = emailInput.getText() != null ? emailInput.getText().toString() : "";
        String password = passwordInput.getText() != null ? passwordInput.getText().toString() : "";

        authRepository.login(email, password, result -> {
            if (result.success) {
                AuthPrefs.save(LoginActivity.this, result.email, result.token);
                startActivity(new Intent(LoginActivity.this, MainActivity.class));
                finish();
            } else {
                setLoading(false);
                setError(result.errorMessage != null ? result.errorMessage : "Login failed");
            }
        });
    }

    private void setLoading(boolean loading) {
        progress.setVisibility(loading ? View.VISIBLE : View.GONE);
        loginButton.setEnabled(!loading);
        emailInput.setEnabled(!loading);
        passwordInput.setEnabled(!loading);
    }

    private void setError(@Nullable String message) {
        if (TextUtils.isEmpty(message)) {
            errorText.setText("");
            errorText.setVisibility(View.GONE);
        } else {
            errorText.setText(message);
            errorText.setVisibility(View.VISIBLE);
        }
    }
}

package com.example.prototype;

import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class MainActivity extends AppCompatActivity {

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        TextView emailView = findViewById(R.id.emailView);
        Button logoutButton = findViewById(R.id.logoutButton);

        String email = AuthPrefs.getEmail(this);
        emailView.setText(email != null ? email : "Unknown");

        logoutButton.setOnClickListener(v -> {
            AuthPrefs.clear(MainActivity.this);
            Intent intent = new Intent(MainActivity.this, LoginActivity.class);
            intent.addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP | Intent.FLAG_ACTIVITY_NEW_TASK);
            startActivity(intent);
            finish();
        });
    }
}

